import React, { useState, useContext } from "react";
import { allProjects } from "../fetchdata/Projects";
import { AppContext } from "../../App";

const SingleComponent = ({ data }) => {
  const { data: ContextData } = useContext(AppContext);
  let { grayOne, grayThree, bgGreenTwo } = ContextData;

  return (
    <div className="col-span-1 mx-2">
      <a href={data.aTag} className="relative">
        <div className="relative overflow-hidden w-full">
          <img className="object-cover w-full" src={data.img} alt="thumbline" />
          <div className="absolute z-10 inset-0 flex items-center justify-center">
            <img
              className="w-10 h-10 md:w-12 md:h-12"
              src={data.demo}
              alt="icon"
            />
          </div>
        </div>
        <div className={`${ContextData.darkMode ? grayOne : grayThree}`}>
          {data.title}
        </div>
        <div className="flex flex-wrap">
          {data.categories.map((category, index) => {
            return (
              <span
                key={index}
                className={`text-custom-small text-gray-800 ${bgGreenTwo} rounded-full p-1 mr-1 my-1`}
              >
                #{category}
              </span>
            );
          })}
        </div>
      </a>
    </div>
  );
};

const ProjectMain = (props) => {
  const [list, setList] = useState(allProjects.slice(0, 2));

  const { data } = useContext(AppContext);
  let { grayOne, grayThree, bgGreenOne } = data;

  const firstSlide = (e) => {
    setList(allProjects.slice(0, 2));
    let allSpan = document.querySelectorAll(".span");
    allSpan.forEach(function (elem) {
      elem.classList.remove(bgGreenOne);
    });
    e.target.classList.add(bgGreenOne);
  };

  const scndSlide = (e) => {
    setList(allProjects.slice(2, 4));
    let allSpan = document.querySelectorAll(".span");
    allSpan.forEach(function (elem) {
      elem.classList.remove(bgGreenOne);
    });
    e.target.classList.add(bgGreenOne);
  };

  const thrdSlide = (e) => {
    setList(allProjects.slice(4, 6));
    let allSpan = document.querySelectorAll(".span");
    allSpan.forEach(function (elem) {
      elem.classList.remove(bgGreenOne);
    });
    e.target.classList.add(bgGreenOne);
  };

  return (
    <>
      <div className="mt-32 mb-6 md:mt-0">
        <div className="grid grid-cols-2">
          {list
            ? list.map((item, index) => {
                return <SingleComponent key={index} data={item} />;
              })
            : ""}
        </div>
        <div className="flex justify-center py-4">
          <span
            onClick={(e) => firstSlide(e)}
            className={`span w-4 h-4 bg-gray-300 ${bgGreenOne} rounded-full mx-1 cursor-pointer`}
          ></span>
          <span
            onClick={(e) => scndSlide(e)}
            className="span w-4 h-4 bg-gray-300 rounded-full mx-1 cursor-pointer"
          ></span>
          <span
            onClick={(e) => thrdSlide(e)}
            className="span w-4 h-4 bg-gray-300 rounded-full mx-1 cursor-pointer"
          ></span>
        </div>
        <div className="flex justify-center items-center text-custom-medium">
          <svg
            className={`${
              data.darkMode ? grayOne : grayThree
            } animate-bounce w-6 h-6 `}
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
            xmlns="http://www.w3.org/2000/svg"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M5 10l7-7m0 0l7 7m-7-7v18"
            />
          </svg>
        </div>
      </div>
    </>
  );
};

export default ProjectMain;
